solution_code:
#include <iostream>
#include <iomanip>

struct Point {
    double x{};
    double y{};
};

class Rectangle {
    Point topLeft;
    Point bottomRight;
public:
    Rectangle(double x1, double y1, double x2, double y2)
        : topLeft{x1, y1}, bottomRight{x2, y2}
    {}

    double area() const {
        return (bottomRight.x - topLeft.x) * (bottomRight.y - topLeft.y);
    }
};

int main() {
    double x1{}, y1{}, x2{}, y2{};
    std::cin >> x1 >> y1 >> x2 >> y2;
    Rectangle r{x1, y1, x2, y2};
    std::cout << std::fixed << std::setprecision(2)
              << "Area: " << r.area() << "\n";
    return 0;
}

